const ALL_KW = [...new Set(DATA.map(r => r.kw))].sort((a,b) => a.toLowerCase().localeCompare(b.toLowerCase()));
const PAGE = 50;

function highlight(text, q) {
  if (!q || !text) return text;
  const i = text.toLowerCase().indexOf(q.toLowerCase());
  if (i === -1) return text;
  return (
    <>
      {text.slice(0,i)}
      <mark>{text.slice(i,i+q.length)}</mark>
      {text.slice(i+q.length)}
    </>
  );
}

export default function App() {
  const [q, setQ] = useState("");
  const [suggestions, setSuggestions] = useState([]);
  const [selected, setSelected] = useState(null);
  const [page, setPage] = useState(1);
  const [showSug, setShowSug] = useState(false);
  const inputRef = useRef();

  useEffect(() => {
    if (!q.trim()) { setSuggestions([]); return; }
    const lo = q.toLowerCase();
    const exact = ALL_KW.filter(k => k.toLowerCase() === lo);
    const starts = ALL_KW.filter(k => k.toLowerCase().startsWith(lo) && k.toLowerCase() !== lo);
    const contains = ALL_KW.filter(k => k.toLowerCase().includes(lo) && !k.toLowerCase().startsWith(lo));
    setSuggestions([...exact, ...starts, ...contains].slice(0, 12));
  }, [q]);

  const results = useMemo(() => {
    if (!selected) return [];
    return DATA.filter(r => r.kw === selected);
  }, [selected]);

  const totalPages = Math.max(1, Math.ceil(results.length / PAGE));
  const pageData = results.slice((page-1)*PAGE, page*PAGE);

  function pick(kw) { setSelected(kw); setQ(kw); setShowSug(false); setPage(1); }
  function clear() { setQ(""); setSelected(null); setSuggestions([]); setPage(1); inputRef.current?.focus(); }

  return (
    <div style={{maxWidth:720,margin:"0 auto",padding:"40px 24px",fontFamily:"var(--font-sans)"}}>
      <h1 style={{fontSize:22,fontWeight:500,marginBottom:4}}>Keyword search</h1>
      <p style={{fontSize:13,color:"var(--color-text-secondary)",marginBottom:24}}>
        {ALL_KW.length.toLocaleString()} unique keywords · {DATA.length.toLocaleString()} author-keyword entries
      </p>

      <div style={{position:"relative",marginBottom:24}}>
        <i className="ti ti-tag" style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",fontSize:16,color:"var(--color-text-tertiary)",pointerEvents:"none"}} />
        <input
          ref={inputRef}
          type="text"
          placeholder="Type a keyword, topic, or research area…"
          value={q}
          onChange={e => { setQ(e.target.value); setSelected(null); setShowSug(true); setPage(1); }}
          onFocus={() => setShowSug(true)}
          onBlur={() => setTimeout(() => setShowSug(false), 150)}
          style={{width:"100%",paddingLeft:34}}
          aria-label="Search keywords"
        />
        {q && (
          <button onClick={clear} style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",padding:4}} aria-label="Clear">
            <i className="ti ti-x" style={{fontSize:16}} />
          </button>
        )}

        {showSug && suggestions.length > 0 && !selected && (
          <div style={{
            position:"absolute",top:"calc(100% + 4px)",left:0,right:0,zIndex:50,
            background:"var(--color-background-primary)",
            border:"0.5px solid var(--color-border-secondary)",
            borderRadius:"var(--border-radius-lg)",
            overflow:"hidden"
          }}>
            {suggestions.map(kw => {
              const count = DATA.filter(r => r.kw === kw).length;
              return (
                <div key={kw} onMouseDown={() => pick(kw)} style={{
                  display:"flex",alignItems:"center",justifyContent:"space-between",
                  padding:"9px 14px",cursor:"pointer",gap:8
                }}
                onMouseEnter={e => e.currentTarget.style.background="var(--color-background-secondary)"}
                onMouseLeave={e => e.currentTarget.style.background="transparent"}>
                  <span style={{fontSize:14}}>{highlight(kw, q)}</span>
                  <span style={{fontSize:12,padding:"2px 8px",borderRadius:"var(--border-radius-md)",background:"var(--color-background-secondary)",color:"var(--color-text-secondary)",whiteSpace:"nowrap"}}>
                    {count} {count===1?"person":"people"}
                  </span>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {selected && (
        <>
          <div style={{display:"flex",alignItems:"baseline",gap:8,marginBottom:12}}>
            <span style={{fontSize:15,fontWeight:500}}>{selected}</span>
            <span style={{fontSize:13,color:"var(--color-text-secondary)"}}>{results.length} {results.length===1?"researcher":"researchers"}</span>
          </div>
          <div style={{border:"0.5px solid var(--color-border-tertiary)",borderRadius:"var(--border-radius-lg)",overflow:"hidden"}}>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1.5fr",padding:"8px 16px",background:"var(--color-background-secondary)",borderBottom:"0.5px solid var(--color-border-tertiary)"}}>
              <div style={{fontSize:12,fontWeight:500,color:"var(--color-text-secondary)"}}>First name</div>
              <div style={{fontSize:12,fontWeight:500,color:"var(--color-text-secondary)"}}>Last name</div>
              <div style={{fontSize:12,fontWeight:500,color:"var(--color-text-secondary)"}}>Email</div>
            </div>
            {pageData.map((r,i) => (
              <div key={r.email+i} style={{
                display:"grid",gridTemplateColumns:"1fr 1fr 1.5fr",
                padding:"10px 16px",alignItems:"center",
                borderBottom: i < pageData.length-1 ? "0.5px solid var(--color-border-tertiary)" : "none"
              }}>
                <div style={{fontSize:14,paddingRight:8,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.first||"—"}</div>
                <div style={{fontSize:14,paddingRight:8,overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.last||"—"}</div>
                <div style={{fontSize:13,color:"var(--color-text-info)",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap"}}>{r.email}</div>
              </div>
            ))}
          </div>
          {totalPages > 1 && (
            <div style={{display:"flex",alignItems:"center",justifyContent:"center",gap:8,padding:"14px 0"}}>
              <button onClick={() => setPage(p => Math.max(1,p-1))} disabled={page===1} aria-label="Previous">
                <i className="ti ti-chevron-left" style={{fontSize:16}} />
              </button>
              <span style={{fontSize:13,color:"var(--color-text-secondary)",minWidth:120,textAlign:"center"}}>Page {page} of {totalPages}</span>
              <button onClick={() => setPage(p => Math.min(totalPages,p+1))} disabled={page===totalPages} aria-label="Next">
                <i className="ti ti-chevron-right" style={{fontSize:16}} />
              </button>
            </div>
          )}
        </>
      )}

      {!selected && !q && (
        <div style={{textAlign:"center",padding:"60px 0",color:"var(--color-text-tertiary)"}}>
          <i className="ti ti-tag" style={{fontSize:40,display:"block",marginBottom:12,opacity:0.3}} />
          <div style={{fontSize:14}}>Start typing to search keywords</div>
        </div>
      )}

      {q && !selected && suggestions.length === 0 && (
        <div style={{textAlign:"center",padding:"60px 0",color:"var(--color-text-tertiary)"}}>
          <i className="ti ti-search-off" style={{fontSize:40,display:"block",marginBottom:12,opacity:0.3}} />
          <div style={{fontSize:14}}>No keywords matching "{q}"</div>
        </div>
      )}
    </div>
  );
}
